import React, { useState, memo } from 'react';
import { Info } from 'lucide-react';
import type { RheoCycle } from '@/lib/analysis/types';
import type { GraceCycleResult } from '@/lib/analysis/types';
import { useUIMode } from '@/contexts/ui-mode-context';
import { useAnalysisSettingsStore } from '@/lib/store/analysis-settings-store';
import { useChartSettingsStore, formatTime, timeUnitLabel } from '@/lib/store/chart-settings-store';
import type { UnitSystem } from '@/lib/store/display-settings-store';
import { DEFAULT_VISCOSITY_SHEAR_RATES } from '@/lib/analysis/constants';
import { CycleRow } from './CycleRow';
import { CycleStepsDetail } from './CycleStepsDetail';

interface CycleResultsTableProps {
    cycles: RheoCycle[];
    results: Map<number, GraceCycleResult>;
    onEditCycle?: (cycleId: number) => void;
}

export const CycleResultsTable = memo(function CycleResultsTable({ cycles, results, onEditCycle }: CycleResultsTableProps) {
    const { isExpert } = useUIMode();
    const expertSettings = useAnalysisSettingsStore(s => s.expertSettings);
    const rUnits = useChartSettingsStore(s => s.settings.rheologyUnits);
    const viscUnit = rUnits.viscosity;
    const unitSystem: UnitSystem = viscUnit === 'Pa·s' ? 'SI_Pas' : viscUnit === 'cP' ? 'Imperial' : 'SI';
    const [expandedCycles, setExpandedCycles] = useState<Set<number>>(new Set());

    // In basic mode, force default shear rates [40, 100, 170] like C# WPF version
    const viscosityRates = (isExpert
        ? (expertSettings.viscosityShearRates || [...DEFAULT_VISCOSITY_SHEAR_RATES])
        : [...DEFAULT_VISCOSITY_SHEAR_RATES]
    ).filter(r => r > 0);

    const toggleCycle = (cycleId: number) => {
        setExpandedCycles(prev => {
            const next = new Set(prev);
            if (next.has(cycleId)) next.delete(cycleId);
            else next.add(cycleId);
            return next;
        });
    };

    if (cycles.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center h-40 text-muted-foreground">
                <Info className="w-8 h-8 mb-2 opacity-50" />
                <p>Нет циклов для отображения</p>
                {!isExpert && <p className="text-sm">Попробуйте режим Эксперт</p>}
            </div>
        );
    }

    // Calculate colspan for expanded details
    // Base: expand(1) + cycle(1) + type(1) + time(1) + dur(1) + n'(1) + K'(1) + Ks(1) + Kp(1) + R²(1) = 10
    const baseColCount = 10 + viscosityRates.length;
    // Expert adds PV(1)+YP(1)+R²Bingham(1)=+3, plus edit button only when onEditCycle is provided
    const detailColSpan = isExpert
        ? baseColCount + 3 + (onEditCycle ? 1 : 0)
        : baseColCount;

    return (
        <div className="overflow-hidden">
            <div className="overflow-x-auto max-h-[450px]">
                <table className="w-full text-sm border-collapse">
                    <thead className="sticky top-0 z-10">
                        <tr className="border-b border-border bg-card">
                            <th className="w-10 py-2 px-2"></th>
                            <th className="w-[60px] py-2 px-2 text-center text-xs font-semibold text-foreground">Цикл</th>
                            <th className="w-28 py-2 px-2 text-center text-xs font-semibold text-foreground">Паттерн</th>
                            <th className="min-w-[80px] py-2 px-2 text-center text-xs font-semibold text-foreground whitespace-nowrap">{(() => { const u = timeUnitLabel(rUnits.timeFormat); return u ? `Время (${u})` : 'Время'; })()}</th>
                            <th className="min-w-[60px] py-2 px-2 text-center text-xs font-semibold text-foreground whitespace-nowrap">Длит. (с)</th>
                            <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground">
                                <span className="cursor-help" title="Индекс течения (n')">n'</span>
                            </th>
                            <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                <span className="cursor-help" title="Индекс консистенции (K')">K' ({rUnits.consistency})</span>
                            </th>
                            <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                <span className="cursor-help" title="K slot — коэффициент для щели/трещины (ISO 13503-1 ф. 15)">Ks ({rUnits.consistency})</span>
                            </th>
                            <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                <span className="cursor-help" title="K pipe — коэффициент для трубы (ISO 13503-1 ф. 16)">Kp ({rUnits.consistency})</span>
                            </th>
                            <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground">
                                <span className="cursor-help" title="Коэффициент детерминации">R²</span>
                            </th>
                            {/* Dynamic viscosity columns */}
                            {viscosityRates.map(rate => (
                                <th key={rate} className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-cyan-700 dark:text-cyan-400 whitespace-nowrap">
                                    <span className="cursor-help" title={`Вязкость при ${rate} с⁻¹`}>η@{rate} ({viscUnit})</span>
                                </th>
                            ))}
                            {/* Expert mode: Bingham model columns */}
                            {isExpert && (
                                <>
                                    <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                        <span className="cursor-help" title="Пластическая вязкость">PV ({rUnits.plasticViscosity})</span>
                                    </th>
                                    <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                        <span className="cursor-help" title="Предел текучести">YP ({rUnits.yieldPoint})</span>
                                    </th>
                                    <th className="min-w-[80px] py-2 px-3 text-center text-xs font-semibold text-foreground whitespace-nowrap">
                                        <span className="cursor-help" title="Модель Бингама R²">R² Bingham</span>
                                    </th>
                                </>
                            )}
                            {isExpert && onEditCycle && (
                                <th className="w-10 py-2 px-2"></th>
                            )}
                        </tr>
                    </thead>
                    <tbody>
                        {cycles.map((cycle) => {
                            const result = results.get(cycle.id);
                            const isExpanded = expandedCycles.has(cycle.id);

                            return (
                                <React.Fragment key={cycle.id}>
                                    <CycleRow
                                        cycle={cycle}
                                        result={result}
                                        isExpanded={isExpanded}
                                        isExpert={isExpert}
                                        viscosityRates={viscosityRates}
                                        unitSystem={unitSystem}
                                        timeFormat={rUnits.timeFormat}
                                        onToggle={() => toggleCycle(cycle.id)}
                                        onEdit={onEditCycle ? () => onEditCycle(cycle.id) : undefined}
                                    />
                                    {isExpanded && (
                                        <CycleStepsDetail
                                            cycleId={cycle.id}
                                            cycleIndex={cycle.cycleIndex || cycle.id}
                                            steps={cycle.steps}
                                            colSpan={detailColSpan}
                                        />
                                    )}
                                </React.Fragment>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
});

import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useDebouncedValue } from '@/hooks/useDebouncedValue';
import { useTheme } from '@/contexts/theme-context';
import { UPlotChart } from '../charts/uplot-chart';
import { ChartBrush } from '../charts/chart-brush';
import { tooltipPlugin } from '../charts/plugins/tooltip';
import { zoomPlugin } from '../charts/plugins/zoom';
import { touchPointsPlugin } from '../charts/plugins/touchPoints';
import { useChartSettingsStore, timeUnitLabel } from '@/lib/store/chart-settings-store';
import type { TimeDisplayFormat } from '@/lib/store/chart-settings-types';
import { useChartResize } from '@/hooks/useChartResize';
import type uPlot from 'uplot';
import { ComparisonLegend } from './ComparisonLegend';
import { type ComparisonChartProps } from './comparison-chart-constants';
import { useComparisonChartData } from './useComparisonChartData';

function ComparisonChartUPlotInner({
    experiments,
    primaryMetric = 'viscosity_cp',
    leftSecondaryMetric = 'none',
    secondaryMetric = 'none',
    tertiaryMetric = 'none',
    showLegend = true,
    showTouchPoints = false,
    viscosityThreshold = 200,
    showTargetTime = true,
    targetTime = 10
}: ComparisonChartProps) {
    const chartContainerRef = useRef<HTMLDivElement | null>(null);
    const chartSize = useChartResize(chartContainerRef);
    // Fallback `'individual'` mirrors the store default
    // (`chart-settings-defaults.ts`: `comparisonAxisMode: 'individual'`) and
    // matches the report-export fallback in `useComparisonReportExport.ts`.
    // Using `'shared'` here silently collapses extra metrics (e.g. a
    // shear-rate left-secondary) onto the viscosity scale whenever the
    // persisted store is missing this key.
    const comparisonAxisMode = useChartSettingsStore(s => s.settings.comparisonAxisMode ?? 'individual');
    const chartSettings = useChartSettingsStore(s => s.settings);
    const { resolvedTheme } = useTheme();
    const isDark = resolvedTheme === 'dark';
    const uPlotRef = useRef<uPlot | null>(null);

    // Debounce rapid experiment additions/removals (e.g. user adds 4 experiments
    // in quick succession).  Without this, each addition triggers a full uPlot
    // destroy+create cycle — leaving N lazy-GC GPU textures (~70 MB each) alive
    // simultaneously.  150 ms covers typical click-through speed; the list
    // re-renders instantly, only chart GPU recreation is deferred.
    const debouncedExperiments = useDebouncedValue(experiments, 150);

    /**
     * Brush range is stored in BOTH a mutable ref and React state:
     * - `brushRangeRef` — read synchronously by the x-scale `auto()` function
     *   inside uPlot's redraw pipeline, and by event handlers before any React
     *   re-render occurs. This is the source of truth for uPlot.
     * - `brushRange` state — drives only the ChartBrush component's UI
     *   (handle positions, range labels). It NEVER feeds back into setScale
     *   via a useEffect, avoiding the async batching / effect-chain races.
     */
    const brushRangeRef = useRef<[number, number] | null>(null);
    const [brushRange, setBrushRange] = useState<[number, number] | null>(null);
    const [hiddenSeries, setHiddenSeries] = useState<Set<number>>(new Set());
    // Use ref instead of state for hovered legend item to avoid React re-renders
    // on every mouse-enter/leave event. Opacity is set directly on DOM elements.

    const [plotBbox, setPlotBbox] = useState<{ left: number; width: number }>({ left: 0, width: 0 });

    const isChartContainerReady = chartSize.width > 8 && chartSize.height > 8;

    /** Restore the full data range on the x-axis and clear the brush. */
    const resetZoom = useCallback((u: uPlot) => {
        brushRangeRef.current = null;
        const times = u.data[0] as number[] | undefined;
        if (times && times.length > 0) {
            u.setScale('x', { min: times[0], max: times[times.length - 1] });
        }
        setBrushRange(null);
    }, []);

    /** Read the plot-area bounding box from the live uPlot instance. */
    const readPlotBbox = useCallback((u: uPlot) => {
        if (!u.bbox) return;
        const dpr = window.devicePixelRatio || 1;
        const left = u.bbox.left / dpr;
        const width = u.bbox.width / dpr;
        setPlotBbox(prev =>
            prev.left === left && prev.width === width ? prev : { left, width },
        );
    }, []);

    const handleChartInit = useCallback((u: uPlot) => {
        uPlotRef.current = u;
        readPlotBbox(u);
        // Two-frame deferred re-read: the first RAF is consumed by React's commit;
        // the second frame captures the final axis layout (y-axis label widths are
        // only known after the first paint, so u.bbox.left may be wrong on frame 0).
        // Store RAF IDs so they can be cancelled if the component unmounts between frames.
        const rafId1 = requestAnimationFrame(() => {
            const rafId2 = requestAnimationFrame(() => {
                if (uPlotRef.current === u) readPlotBbox(u);
            });
            pendingRafs.current.push(rafId2);
        });
        pendingRafs.current.push(rafId1);
        if (brushRangeRef.current) {
            u.setScale('x', { min: brushRangeRef.current[0], max: brushRangeRef.current[1] });
        }
    }, [readPlotBbox]);

    // Track pending RAF IDs for cleanup on unmount
    const pendingRafs = useRef<number[]>([]);

    // Clear the uPlot ref on unmount so stale callbacks (toggleSeries, brush)
    // never call methods on a destroyed instance after navigation.
    // Also cancel any pending RAFs to prevent closures from holding references
    // to destroyed uPlot instances.
    useEffect(() => {
        return () => {
            uPlotRef.current = null;
            pendingRafs.current.forEach(id => cancelAnimationFrame(id));
            pendingRafs.current = [];
        };
    }, []);

    // Re-read plot bbox after container resize
    useEffect(() => {
        const raf = requestAnimationFrame(() => {
            if (uPlotRef.current) readPlotBbox(uPlotRef.current);
        });
        return () => cancelAnimationFrame(raf);
    }, [chartSize.width, chartSize.height, readPlotBbox]);

    /**
     * Called by ChartBrush on every pointer-move during drag.
     * Directly calls setScale — no React state update in the hot path,
     * so uPlot's microtask commit fires without any React re-render racing.
     * `brushRange` state is updated separately only to drive the brush UI.
     */
    const handleBrushChange = useCallback((min: number, max: number) => {
        brushRangeRef.current = [min, max];
        const u = uPlotRef.current;
        if (u) {
            u.batch(() => {
                u.setScale('x', { min, max });
            });
        }
        setBrushRange([min, max]);
    }, []);

    const handleBrushReset = useCallback(() => {
        const u = uPlotRef.current;
        if (u) resetZoom(u);
        else {
            brushRangeRef.current = null;
            setBrushRange(null);
        }
    }, [resetZoom]);

    // Reset brush and hidden series when experiments change (add/remove)
    const expIds = experiments.map(e => e.id).join(',');
    useEffect(() => {
        brushRangeRef.current = null;
        setBrushRange(null);
        setHiddenSeries(new Set());
    }, [expIds]);

    const toggleSeries = useCallback((legendIndex: number) => {
        const uPlotSeriesIndex = legendIndex + 1; // uPlot index 0 = time axis
        setHiddenSeries(prev => {
            const next = new Set(prev);
            const nowHidden = !next.has(legendIndex);
            if (nowHidden) next.add(legendIndex); else next.delete(legendIndex);
            uPlotRef.current?.setSeries(uPlotSeriesIndex, { show: !nowHidden });
            return next;
        });
    }, []);

    const { uPlotData, seriesConfig, axesConfig, touchPoints } = useComparisonChartData({
        debouncedExperiments,
        primaryMetric,
        leftSecondaryMetric,
        secondaryMetric,
        tertiaryMetric,
        showTouchPoints,
        viscosityThreshold,
        showTargetTime,
        targetTime,
        comparisonAxisMode,
    });

    // Brush width = plot-area width as reported by uPlot bbox.
    // Fall back to (container - leftAxis - 20px default right padding) only when
    // bbox isn't populated yet (first render before drawAxes fires).
    const brushWidth = plotBbox.width > 0
        ? plotBbox.width
        : Math.max(0, chartSize.width - plotBbox.left - 20);
    // Right margin = space occupied by right-side axes (Temperature axis etc.)
    const brushPaddingRight = plotBbox.width > 0
        ? Math.max(0, chartSize.width - plotBbox.left - plotBbox.width)
        : 20;

    const uPlotOptions = useMemo<uPlot.Options>(() => {
        // x-scale: allow auto-ranging only when no brush is active.
        // When brush is active `auto()` returns false, so uPlot's internal
        // setData(data, true) calls `_setScale('x', currentMin, currentMax)`
        // instead of `autoScaleX()` — preserving the zoomed window.
        // `range` simply passes through whatever min/max are given so explicit
        // setScale calls from handleBrushChange are respected verbatim.
        const scales: Record<string, uPlot.Scale> = {
            x: {
                time: false,
                auto: (_u: uPlot) => brushRangeRef.current === null,
                range: (_u: uPlot, dataMin: number, dataMax: number) => {
                    const br = brushRangeRef.current;
                    return br ?? [dataMin, dataMax];
                },
            },
        };
        // Register y-scales from axes config
        axesConfig.forEach(a => {
            if (a.scale && a.scale !== 'x') {
                scales[a.scale] = { auto: true };
            }
        });

        // In individual mode, the viscosity scale auto-ranges to actual data values
        // (e.g. 500–1400 cP), which may exclude the threshold (e.g. 200 cP).
        // Expand the scale range to always include the threshold so the reference
        // line is visible regardless of the data range.
        if (showTouchPoints && viscosityThreshold !== undefined && comparisonAxisMode !== 'shared') {
            const viscSN = primaryMetric; // scale name = metric key in individual mode
            if (scales[viscSN]) {
                scales[viscSN] = {
                    auto: true,
                    range: (_u: uPlot, dataMin: number, dataMax: number) => {
                        const mn = Math.min(dataMin, viscosityThreshold);
                        const mx = Math.max(dataMax, viscosityThreshold);
                        const pad = (mx - mn) * 0.06 || 1;
                        return [mn - pad, mx + pad];
                    }
                };
            }
        }

        return {
            width: 100,
            height: 100,
            // Cap device pixel ratio at 1.5 — avoids 4× GPU texture scaling on HiDPI
            // displays (DPR=2 → 2560×1400 backing store) while keeping text crisp.
            pxRatio: Math.min(window.devicePixelRatio || 1, 1.5),
            padding: [10, 20, 10, 10],
            legend: { show: false },
            cursor: {
                points: { size: 8, width: 2, stroke: '#fff' }
            },
            plugins: [
                {
                    // Keep plotBbox in sync whenever uPlot redraws axes (resize, first paint).
                    // readPlotBbox only calls setPlotBbox when values actually change, so
                    // this never triggers spurious React re-renders.
                    hooks: {
                        drawAxes: [(u: uPlot) => { readPlotBbox(u); }],
                    },
                },
                tooltipPlugin({
                    titleFormatter: (val: number) => {
                        const timeFmt: TimeDisplayFormat = chartSettings.rheologyUnits?.timeFormat ?? 'seconds';
                        let formatted: string;
                        switch (timeFmt) {
                            case 'seconds': formatted = String(Math.round(val * 60)); break;
                            case 'hh:mm:ss': {
                                const ts = Math.round(val * 60);
                                const h = Math.floor(ts / 3600);
                                const m = Math.floor((ts % 3600) / 60);
                                const s = ts % 60;
                                formatted = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
                                break;
                            }
                            default: formatted = String(Math.round(val * 10) / 10);
                        }
                        return `Время: ${formatted} ${timeUnitLabel(timeFmt)}`;
                    },
                    isDark,
                }),
                zoomPlugin({
                    // zoomPlugin already called setScale internally; we only need
                    // to sync brushRangeRef and refresh the brush UI.
                    onZoom: (min, max) => {
                        brushRangeRef.current = [min, max];
                        setBrushRange([min, max]);
                    },
                    onReset: () => {
                        brushRangeRef.current = null;
                        setBrushRange(null);
                    },
                }),
                touchPointsPlugin({
                    touchPoints,
                    viscosityThreshold,
                    // Comparison chart Y-scale for viscosity is always cP
                    // (primary metric is `viscosity_cp`), so the plugin's
                    // threshold conversion is an identity here.  Stating
                    // it explicitly keeps the contract clear and future-
                    // proof if per-experiment unit selectors are added.
                    displayUnit: 'cP',
                    showTouchPoints,
                    targetTime,
                    isDark,
                    scaleName: comparisonAxisMode === 'shared' ? 'left' : primaryMetric,
                })
            ],
            scales,
            axes: axesConfig,
            series: seriesConfig
        };
    }, [axesConfig, seriesConfig, touchPoints, viscosityThreshold, showTouchPoints, targetTime, primaryMetric, comparisonAxisMode, readPlotBbox, isDark]);

    return (
        <div className="flex flex-col h-full w-full">
            <div ref={chartContainerRef} className="flex-1 min-h-0 relative overflow-hidden" data-testid="ComparisonChart" role="img" aria-label="График сравнения экспериментов">
                {isChartContainerReady && uPlotData[0].length > 0 ? (
                    <div className="absolute inset-0">
                        <UPlotChart 
                            options={uPlotOptions} 
                            data={uPlotData}
                            resetScalesOnDataChange={false}
                            width={chartSize.width} 
                            height={chartSize.height}
                            onInit={handleChartInit}
                        />
                    </div>
                ) : (
                    <div className="absolute inset-0 flex items-center justify-center text-muted-foreground">
                        {experiments.length === 0 ? 'Добавьте эксперименты для сравнения' : 'Загрузка данных...'}
                    </div>
                )}
            </div>

            {/* Brush / range selector – aligned with the plot area */}
            {experiments.length > 0 && uPlotData[0].length > 0 && brushWidth > 0 && (
                <div className="flex-none py-1" style={{ paddingLeft: plotBbox.left, paddingRight: brushPaddingRight }}>
                    <ChartBrush
                        times={uPlotData[0] as number[]}
                        values={uPlotData[1] as (number | null)[]}
                        range={brushRange}
                        onChange={handleBrushChange}
                        onReset={handleBrushReset}
                        width={brushWidth}
                        height={36}
                    />
                </div>
            )}

            {/* Custom Legend */}
            {showLegend && experiments.length > 0 && (
                <ComparisonLegend
                    seriesConfig={seriesConfig}
                    hiddenSeries={hiddenSeries}
                    toggleSeries={toggleSeries}
                />
            )}
        </div>
    );
}

/**
 * Memoised export — prevents full chart rebuild when parent re-renders due to
 * displaySettings changes (axis picks, legend toggle). The inner debounce
 * (150 ms) handles rapid experiment additions; memo handles everything else.
 */
export const ComparisonChartUPlot = React.memo(ComparisonChartUPlotInner);

/**
 * UpdateChecker.tsx
 *
 * Invisible component that silently polls for updates in the background.
 * - On mount: waits 30 s, then calls the Tauri updater endpoint.
 * - If an update is found: stores it for later installation and notifies the
 *   update-store so UpdateBanner can show the prompt.
 * - On error (network down, server unreachable, etc.): fails silently.
 * - Repeats the check every 4 hours while the app is open.
 *
 * Installation is triggered by `startUpdateInstall()` (called by UpdateBanner).
 */

import { useEffect, useRef } from 'react';
import { check } from '@tauri-apps/plugin-updater';
import { invoke } from '@tauri-apps/api/core';
import { listen } from '@tauri-apps/api/event';
import { logger } from '@/lib/logger';
import { isTauri } from '@/lib/tauri';
import { useUpdateStore, type StartupCompletedPayload } from '@/lib/store/update-store';
import { setPendingUpdate } from './update-install';

// Re-export the install/relaunch helpers so existing callers that imported
// them from `./UpdateChecker` continue to work — but prefer the lazy
// `./update-install` path when you are about to add a new call site.
export { startUpdateInstall, relaunchApp } from './update-install';

// Delay before first check after app startup (ms)
const INITIAL_DELAY_MS = 30_000;
// Interval between subsequent checks (ms)
const CHECK_INTERVAL_MS = 4 * 60 * 60 * 1000;

/** Returns the update channel and a verifiable HMAC token from the cached license. */
async function getUpdateChannelInfo(): Promise<{ channel: string; token: string | null }> {
    try {
        return await invoke<{ channel: string; token: string | null }>('get_update_channel');
    } catch {
        return { channel: 'stable', token: null };
    }
}

/** Builds request headers forwarded to the update server. */
function buildUpdateHeaders(info: { channel: string; token: string | null }): Record<string, string> {
    const headers: Record<string, string> = { 'X-Update-Channel': info.channel };
    if (info.token) headers['X-Update-Token'] = info.token;
    return headers;
}

/**
 * Trigger an immediate update check (called from Settings → О программе).
 * Safe to call at any time — no-ops if already checking/installing.
 */
export async function checkUpdateNow(): Promise<void> {
    const store = useUpdateStore.getState();
    if (
        store.status === 'checking' ||
        store.status === 'downloading' ||
        store.status === 'ready'
    ) return;
    // Reset stale error so we can retry
    if (store.status === 'error') store.reset();

    try {
        store.startCheck();
        const info = await getUpdateChannelInfo();
        const update = await check({ headers: buildUpdateHeaders(info) });
        if (update?.available) {
            setPendingUpdate(update);
            const notes = update.body?.trim() ?? null;
            store.setAvailable(update.version, notes);
            logger.info(`[UpdateChecker] Manual check — update available: v${update.version}`);
        } else {
            store.reset();
            logger.info('[UpdateChecker] Manual check — up to date');
        }
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        // Surface the error so the user sees it instead of a misleading
        // "up to date" message.  The background auto-check still resets
        // silently (offline is expected), but manual checks should be honest.
        store.setError(`Не удалось проверить: ${msg}`);
        logger.error(`[UpdateChecker] Manual check failed: ${msg}`);
    }
}

export function UpdateChecker(): null {
    const hasStarted = useRef(false);
    const isE2ERef = useRef(false);

    useEffect(() => {
        // Only run inside the actual Tauri desktop app, not in browser/tests.
        if (!isTauri() || hasStarted.current) return;
        hasStarted.current = true;

        let unlistenStartup: (() => void) | undefined;
        let initialTimer: ReturnType<typeof setTimeout> | null = null;
        let intervalId: ReturnType<typeof setInterval> | null = null;
        let cancelled = false;

        async function runCheck(): Promise<void> {
            // Hard stop in E2E — avoid any network / WebView navigation side-effects.
            if (isE2ERef.current) return;
            const store = useUpdateStore.getState();
            // Skip if an update is already pending or being installed.
            if (store.status !== 'idle') return;

            try {
                store.startCheck();
                const info = await getUpdateChannelInfo();
                const update = await check({ headers: buildUpdateHeaders(info) });

                if (update?.available) {
                    setPendingUpdate(update);
                    const notes = update.body?.trim() ?? null;
                    store.setAvailable(update.version, notes);
                    logger.info(
                        `[UpdateChecker] Update available: v${update.version}`,
                    );
                } else {
                    store.reset();
                }
            } catch (err) {
                // Network / server errors are expected when offline — reset quietly.
                store.reset();
                logger.error(
                    `[UpdateChecker] Background check failed: ${String(err)}`,
                );
            }
        }

        // Resolve E2E flag first so we can skip side-effects entirely in tests.
        // Then register the startup_completed listener and schedule the timer.
        (async () => {
            // Suppress the auto-updater entirely in E2E test environments.
            // The updater can trigger a WebView2 navigation to `edge://downloads/hub`
            // mid-run, which breaks CDP-based Playwright fixtures. The Rust
            // backend flags E2E mode via `RHEOLAB_E2E_SKIP_LICENSE_GATE=1`.
            try {
                isE2ERef.current = await invoke<boolean>('is_e2e_mode');
            } catch {
                isE2ERef.current = false;
            }
            if (cancelled) return;

            if (isE2ERef.current) {
                logger.info('[UpdateChecker] E2E mode detected — auto-updater disabled');
                // Still register the startup_completed listener: tests may assert on it.
            }

            // Subscribe to the startup_completed event emitted by lib.rs ~500 ms
            // after launch.  When version_changed is true the user has just run
            // the app for the first time after an update — show recovery banner.
            try {
                const unlisten = await listen<StartupCompletedPayload>('startup_completed', ({ payload }) => {
                    if (payload.versionChanged && payload.previousAppVersion) {
                        useUpdateStore.getState().setPostUpdate(
                            payload.previousAppVersion,
                            payload.appVersion,
                        );
                        logger.info(
                            `[UpdateChecker] Post-update first run: ${payload.previousAppVersion} → ${payload.appVersion}`,
                        );
                    }
                });
                if (cancelled) { unlisten(); return; }
                unlistenStartup = unlisten;
            } catch (err) {
                logger.warn(`[UpdateChecker] Failed to register startup_completed listener: ${String(err)}`);
            }

            // In E2E mode stop here — no background timer.
            if (isE2ERef.current) return;

            initialTimer = setTimeout(() => {
                void runCheck();
                intervalId = setInterval(runCheck, CHECK_INTERVAL_MS);
            }, INITIAL_DELAY_MS);
        })();

        return () => {
            cancelled = true;
            if (initialTimer !== null) clearTimeout(initialTimer);
            if (intervalId !== null) clearInterval(intervalId);
            unlistenStartup?.();
        };
    }, []);

    return null;
}

/**
 * useRheologyChartOptions
 *
 * Builds the uPlot.Options object for the RheologyChart component.
 * Thin orchestrator — delegates translations, axes, and series assembly
 * to dedicated modules in `./chart-options/`.
 */
import { useMemo, useRef } from 'react';
import type uPlot from 'uplot';
import { tooltipPlugin } from '@/components/charts/plugins/tooltip';
import { zoomPlugin } from '@/components/charts/plugins/zoom';
import { touchPointsPlugin, type TouchPointsPluginOptions } from '@/components/charts/plugins/touchPoints';
import type { ChartSettings } from '@/lib/store/chart-settings-store';
import type { TimeDisplayFormat, ViscosityUnit } from '@/lib/store/chart-settings-types';
import type { TouchPointMarker } from './useRheologyData';
import { useTheme } from '@/contexts/theme-context';
import { buildAxes, buildChartTranslations, buildSeries } from './chart-options';

interface UseRheologyChartOptionsParams {
    activeSettings: ChartSettings;
    chartSettings: ChartSettings;
    showTemperature: boolean;
    showShearRate: boolean;
    showPressure: boolean;
    showRpm: boolean;
    showBathTemperature: boolean;
    pdfMode: boolean;
    captureMode: boolean;
    touchPoints: TouchPointMarker[];
    effectiveShearRateAxis: 'left' | 'right';
    effectivePressureAxis: 'left' | 'right';
    axisMode: 'shared' | 'individual';
    /**
     * Viscosity threshold in **cP** (algorithm canonical unit).  The
     * touch-points plugin converts this to the chart's current display
     * unit before calling `valToPos`, so the horizontal guide always
     * lines up with the correct pixel regardless of the Y-scale unit.
     */
    viscosityThreshold: number;
    /** Chart display unit of the viscosity Y axis. */
    viscosityDisplayUnit: ViscosityUnit;
    showTouchPoints: boolean;
    targetTime: number;
    language?: 'ru' | 'en';
}

export function useRheologyChartOptions({
    activeSettings,
    chartSettings,
    showTemperature,
    showShearRate,
    showPressure,
    showRpm,
    showBathTemperature,
    pdfMode,
    captureMode,
    touchPoints,
    effectiveShearRateAxis,
    effectivePressureAxis,
    axisMode,
    viscosityThreshold,
    viscosityDisplayUnit,
    showTouchPoints,
    targetTime,
    language = 'ru',
}: UseRheologyChartOptionsParams): uPlot.Options {
    const { resolvedTheme } = useTheme();

    // ── Touch-points ref ──────────────────────────────────────────────────
    // Touch-point overlay data changes on every analysis run (new array ref).
    // Putting it directly in the useMemo deps would trigger a full chart
    // destroy → recreate cycle, leaking DOM nodes and causing a visible flash.
    // Instead, keep the volatile values in a ref that the draw-hook reads
    // on every uPlot repaint. The chart still repaints (via setData) so the
    // overlay always reflects the latest data — without recreation.
    const touchPointsRef = useRef<TouchPointsPluginOptions>({
        touchPoints,
        viscosityThreshold,
        displayUnit: viscosityDisplayUnit,
        showTouchPoints,
        targetTime,
        pdfMode,
        captureMode,
        scaleName: undefined, // will be set inside the memo
    });
    // Sync on every render — cheap object assignment.
    touchPointsRef.current = {
        touchPoints,
        viscosityThreshold,
        displayUnit: viscosityDisplayUnit,
        showTouchPoints,
        targetTime,
        pdfMode,
        captureMode,
        isDark: resolvedTheme === 'dark',
        language,
        scaleName: touchPointsRef.current.scaleName, // preserve computed scale name
    };

    return useMemo<uPlot.Options>(() => {
        const isDark = !pdfMode && !captureMode && resolvedTheme === 'dark';
        const isShared = axisMode === 'shared';
        const timeFmt: TimeDisplayFormat = chartSettings.rheologyUnits?.timeFormat ?? 'seconds';

        // ── Per-metric uPlot scale names ─────────────────────────────────────
        const sViscosity = isShared ? 'left' : 'viscosity';
        const sTemperature = isShared ? 'right' : 'temperature';
        const sShearRate = isShared ? (effectiveShearRateAxis === 'right' ? 'right' : 'left') : 'shearRate';
        const sPressure = isShared ? (effectivePressureAxis === 'right' ? 'right' : 'left') : 'pressure';
        const sRpm = isShared ? (activeSettings.lines.rpm.axis === 'right' ? 'right' : 'left') : 'rpm';
        // Bath temperature shares the same Y scale as sample temperature (same °C units)
        const sBathTemperature = sTemperature;

        // Update the scaleName in the ref so the draw-hook reads it.
        touchPointsRef.current = { ...touchPointsRef.current, scaleName: sViscosity };

        const t = buildChartTranslations({ activeSettings, chartSettings, language });

        return {
            width: 100, // Initial dummy size, will be overridden by UPlotChart props
            height: 100,
            // Cap device pixel ratio at 1.5 — avoids 4× GPU texture scaling on HiDPI
            // displays (DPR=2 → 2560×1400 backing store) while keeping text crisp.
            pxRatio: Math.min(window.devicePixelRatio || 1, 1.5),
            padding: [10, 20, 10, 10], // [top, right, bottom, left]
            legend: { show: false },
            cursor: {
                points: {
                    size: 8,
                    width: 2,
                    // Use each series' own colour for cursor dot (per-series color)
                    fill: (u: uPlot, si: number) => {
                        const s = u.series[si]?.stroke;
                        return typeof s === 'string' ? s : (isDark ? '#1e293b' : '#fff');
                    },
                    stroke: (u: uPlot, si: number) => {
                        const s = u.series[si]?.stroke;
                        return typeof s === 'string' ? s : (isDark ? '#fff' : '#000');
                    },
                },
            },
            plugins: [
                ...(!captureMode && !pdfMode && chartSettings.tooltipEnabled !== false
                    ? [
                        tooltipPlugin({
                            formatter: (idx: number, val: number) => `${val} ${t.tooltipUnits[idx] ?? ''}`,
                            titleFormatter: (val: number) => t.tooltipTimeLabel(val),
                            isDark,
                        }),
                    ]
                    : []),
                zoomPlugin(),
                touchPointsPlugin(touchPointsRef),
            ],
            scales: {
                x: { time: false },
                ...(isShared
                    ? {
                        left: { auto: true },
                        right: { auto: true },
                    }
                    : {
                        viscosity: { auto: true },
                        temperature: { auto: true },
                        shearRate: { auto: true },
                        pressure: { auto: true },
                        rpm: { auto: true },
                    }),
            },
            axes: buildAxes({
                activeSettings,
                t,
                isDark,
                isShared,
                showTemperature,
                showShearRate,
                showPressure,
                showRpm,
                showBathTemperature,
                effectiveShearRateAxis,
                effectivePressureAxis,
                timeFmt,
            }),
            series: buildSeries({
                activeSettings,
                t,
                showTemperature,
                showShearRate,
                showPressure,
                showRpm,
                showBathTemperature,
                sViscosity,
                sTemperature,
                sShearRate,
                sPressure,
                sRpm,
                sBathTemperature,
            }),
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- touchPoints/showTouchPoints/targetTime/viscosityThreshold/tooltipEnabled are read from a ref inside the draw hook (no chart recreation needed)
    }, [activeSettings, chartSettings, showTemperature, showShearRate, showPressure, showRpm, showBathTemperature, pdfMode, captureMode, effectiveShearRateAxis, effectivePressureAxis, axisMode, resolvedTheme, language]);
}

/**
 * useRheologyVisibility
 *
 * Derives chart visibility flags and active settings from stores and props.
 * Extracted from RheologyChart to keep the component readable.
 */
import { useAnalysisSettingsStore } from '@/lib/store/analysis-settings-store';
import { useChartSettingsStore } from '@/lib/store/chart-settings-store';
import type { ChartSettings } from '@/lib/store/chart-settings-store';

interface UseRheologyVisibilityParams {
    previewMode: boolean;
    captureMode: boolean;
    showTemperatureProp?: boolean;
    showShearRateProp?: boolean;
    showPressureProp?: boolean;
    showRpmProp?: boolean;
    showBathTemperatureProp?: boolean;
    shearRateAxis: 'left' | 'right';
    pressureAxis: 'left' | 'right';
}

export interface RheologyVisibility {
    activeSettings: ChartSettings;
    chartSettings: ChartSettings;
    timeShiftEnabled: boolean;
    showTemperature: boolean;
    showShearRate: boolean;
    showPressure: boolean;
    showRpm: boolean;
    showBathTemperature: boolean;
    effectiveShearRateAxis: 'left' | 'right';
    effectivePressureAxis: 'left' | 'right';
    axisMode: 'shared' | 'individual';
    downsampleMode: string;
}

export function useRheologyVisibility({
    previewMode,
    captureMode,
    showTemperatureProp,
    showShearRateProp,
    showPressureProp,
    showRpmProp,
    showBathTemperatureProp,
    shearRateAxis,
    pressureAxis,
}: UseRheologyVisibilityParams): RheologyVisibility {
    const expertSettings = useAnalysisSettingsStore(s => s.expertSettings);
    const { timeShiftEnabled } = expertSettings;
    const chartSettings = useChartSettingsStore(s => s.settings);

    // Single source of truth: same settings for dashboard and reports
    const activeSettings = chartSettings;

    const showTemperature = showTemperatureProp ?? activeSettings.lines.temperature.visible;
    const showShearRate = showShearRateProp ?? activeSettings.lines.shearRate.visible;
    const showPressure = showPressureProp ?? activeSettings.lines.pressure.visible;
    const showRpm = showRpmProp ?? activeSettings.lines.rpm.visible;
    const showBathTemperature = showBathTemperatureProp ?? (activeSettings.lines.bathTemperature?.visible ?? false);

    const effectiveShearRateAxis = shearRateAxis;
    const effectivePressureAxis = pressureAxis;

    const axisMode = (activeSettings.comparisonAxisMode ?? 'individual') as 'shared' | 'individual';
    const downsampleMode = activeSettings.downsampleMode ?? 'smart';

    return {
        activeSettings,
        chartSettings,
        timeShiftEnabled,
        showTemperature,
        showShearRate,
        showPressure,
        showRpm,
        showBathTemperature,
        effectiveShearRateAxis,
        effectivePressureAxis,
        axisMode,
        downsampleMode,
    };
}

/**
 * Full E2E Workflow — modern rewrite using Page Objects.
 *
 * Covers the complete user journey in browser mode (WASM parsing, mocked IPC):
 *   1. Upload + parse file → verify chart renders
 *   2. Dashboard tab switching (chart / table / recipe / water / calibration)
 *   3. Save experiment to DB (mocked IPC)
 *   4. Library: verify saved experiments appear, test search filter
 *   5. Library: test filter select controls (fluid type, instrument)
 *   6. Single-experiment report generation (PDF + Excel)
 *   7. Comparison: add two experiments, verify chart
 *   8. Comparison report generation + section toggles
 *
 * Run:
 *   npx playwright test tests/e2e/full-workflow.spec.ts
 */

import { test, expect, setupBeforeEach } from './base-test';
import { CHANDLER_SST_63, GRACE_REPORT } from './fixtures';

// ─────────────────────────────────────────────────────────────────────────────

setupBeforeEach(test);

test.describe('Full E2E Workflow', () => {
    test.setTimeout(180_000); // 3 min — WASM parsing + mocked IPC

    // ── Step 1: Upload + parse + verify chart ─────────────────────────
    test('1_upload_parse_chart_renders', async ({ dashboard }) => {
        await dashboard.goto();
        await dashboard.uploadFile(CHANDLER_SST_63);
        await dashboard.waitForAnalysis();
        await dashboard.expectChartVisible();
        await dashboard.expectNoAnalysisError();
        console.log('✓ Chandler parsed, chart rendered');
    });

    // ── Step 2: Dashboard tab switching ───────────────────────────────
    test('2_dashboard_tab_switching', async ({ dashboard }) => {
        await dashboard.goto();
        await dashboard.uploadFile(CHANDLER_SST_63);
        await dashboard.waitForAnalysis();

        for (const tab of ['chart', 'table', 'recipe', 'water', 'calibration'] as const) {
            await dashboard.switchTab(tab);
            console.log(`  ✓ Switched to "${tab}" tab`);
        }
        // Return to chart — should still render
        await dashboard.switchTab('chart');
        await dashboard.expectChartVisible();
    });

    // ── Step 3: Save experiment to DB ─────────────────────────────────
    test('3_save_experiment_to_db', async ({ dashboard }) => {
        await dashboard.goto();
        await dashboard.uploadFile(CHANDLER_SST_63);
        await dashboard.waitForAnalysis();

        const { name } = await dashboard.saveExperiment({ name: `Workflow-Chandler-${Date.now()}` });
        console.log(`✓ Saved experiment "${name}"`);
    });

    // ── Step 4: Library — saved experiments appear + search filter ────
    test('4_library_filters_and_search', async ({ dashboard, library }) => {
        // Save two experiments first
        await dashboard.goto();
        await dashboard.uploadFile(CHANDLER_SST_63);
        await dashboard.waitForAnalysis();
        const exp1 = await dashboard.saveExperiment({ name: `WF-Search-1-${Date.now()}` });

        await dashboard.goto();
        await dashboard.uploadFile(GRACE_REPORT);
        await dashboard.waitForAnalysis();
        const exp2 = await dashboard.saveExperiment({ name: `WF-Search-2-${Date.now()}` });

        // Navigate to Library
        await library.goto();
        await library.expectLoaded();
        await library.expectMinExperimentCount(2);

        // Verify saved experiments appear
        await library.expectExperimentVisible(exp1.name);
        console.log(`✓ "${exp1.name}" visible in library`);

        // Search filter — should narrow results
        await library.search(exp1.name);
        await library.expectExperimentVisible(exp1.name);
        console.log('✓ Search filter works');

        // Clear and verify all come back
        await library.search('');
        await library.expectMinExperimentCount(2);

        // Instrument filter (combobox)
        const instrumentFilter = library.instrumentTypeFilter;
        if (await instrumentFilter.isVisible({ timeout: 3_000 }).catch(() => false)) {
            await instrumentFilter.click();
            const chandlerOpt = library.page.locator('[role="option"]').filter({ hasText: /Chandler/i }).first();
            if (await chandlerOpt.isVisible({ timeout: 2_000 }).catch(() => false)) {
                await chandlerOpt.click();
                await library.waitForListSettled();
                console.log('✓ Instrument filter applied');
            } else {
                await library.page.keyboard.press('Escape');
            }
        }

        // Fluid type filter
        const fluidFilter = library.fluidTypeFilter;
        if (await fluidFilter.isVisible({ timeout: 3_000 }).catch(() => false)) {
            await fluidFilter.click();
            const anyOption = library.page.locator('[role="option"]').first();
            if (await anyOption.isVisible({ timeout: 2_000 }).catch(() => false)) {
                await anyOption.click();
                await library.waitForListSettled();
                console.log('✓ Fluid type filter applied');
            } else {
                await library.page.keyboard.press('Escape');
            }
        }

        // Clear all filters (only if button is visible AND enabled)
        const clearBtn = library.clearFiltersButton;
        if (await clearBtn.isVisible({ timeout: 2_000 }).catch(() => false) &&
            await clearBtn.isEnabled({ timeout: 1_000 }).catch(() => false)) {
            await library.clearAllFilters();
            await library.waitForListSettled();
            console.log('✓ Filters cleared');
        }
    });

    // ── Step 5: Single-experiment report generation (PDF + Excel) ─────
    test('5_single_exp_report_generation', async ({ dashboard, reports }) => {
